import{_ as e,o as r,c as t,a2 as o}from"./chunks/framework.Cr-Z7ngm.js";const _=JSON.parse('{"title":"货币保证金","description":"","frontmatter":{"layout":"doc","sidebar":true},"headers":[],"relativePath":"margin/currency-collateral.md","filePath":"zh-CN/margin/currency-collateral.md"}'),p={name:"margin/currency-collateral.md"};function l(n,a,c,i,h,s){return r(),t("div",null,[...a[0]||(a[0]=[o('<h1 id="货币保证金" tabindex="-1">货币保证金 <a class="header-anchor" href="#货币保证金" aria-label="Permalink to &quot;货币保证金&quot;">​</a></h1><p>当账户持有的货币与投资标的计价货币不同时（如用港元账户购买美元计价的美股），存在汇率波动风险。平台会对此类跨币种持仓额外收取货币保证金。</p><h2 id="货币保证金的触发条件" tabindex="-1">货币保证金的触发条件 <a class="header-anchor" href="#货币保证金的触发条件" aria-label="Permalink to &quot;货币保证金的触发条件&quot;">​</a></h2><p>当某种货币的资产净值为负（即该货币资不抵债）时，触发货币保证金计算。</p><p>货币保证金 = 该货币负债金额 × 货币保证金比率</p><h2 id="货币保证金比率" tabindex="-1">货币保证金比率 <a class="header-anchor" href="#货币保证金比率" aria-label="Permalink to &quot;货币保证金比率&quot;">​</a></h2><p>以下比率以平台实时公示为准：</p><p>美元（USD）：4%</p><p>港元（HKD）：4%</p><h2 id="示例说明" tabindex="-1">示例说明 <a class="header-anchor" href="#示例说明" aria-label="Permalink to &quot;示例说明&quot;">​</a></h2><p>账户存入 20,000 HKD，未持有美元。</p><p>购入价值 2,000 USD 的美股（此时美元持仓为 -2,000 USD，即借入美元）。</p><p>之后美股市值下跌至 1,900 USD。</p><p>此时美元资产净值 = 1,900 USD（持仓市值）- 2,000 USD（借入成本）= -100 USD，即美元资不抵债 100 USD。</p><p>货币保证金 = 100 USD × 4% = 4 USD</p><h2 id="对账户指标的影响" tabindex="-1">对账户指标的影响 <a class="header-anchor" href="#对账户指标的影响" aria-label="Permalink to &quot;对账户指标的影响&quot;">​</a></h2><p>货币保证金会计入以下计算：</p><p>购买力：货币保证金作为额外占用，降低可用购买力。</p><p>出金可用金额：出金时需预留货币保证金，超出部分方可出金。</p><p>追缴保证金：触发追缴时，货币保证金纳入差额计算。</p><p><a href="https://longbridgeapp.com/zh-CN/topics/2078132" target="_blank" rel="noreferrer">参考链接</a></p>',21)])])}const u=e(p,[["render",l]]);export{_ as __pageData,u as default};
